def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import pygmo

    # 设置参考点
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    n, d = points.shape

    # 超体积计算函数
    def compute_hv(subset_indices):
        if len(subset_indices) == 0:
            return 0.0
        subset_points = points[list(subset_indices)]
        hv = pygmo.hypervolume(subset_points)
        return hv.compute(reference_point)

    # 计算单个点的贡献
    def point_contribution(point_idx, current_set):
        if len(current_set) == 0:
            return compute_hv({point_idx})
        new_set = current_set | {point_idx}
        return compute_hv(new_set) - compute_hv(current_set)

    # 初始化种群
    population_size = 20
    population = []

    # 创建初始解（不同大小的子集）
    for _ in range(population_size):
        size = random.randint(max(1, k-2), min(n, k+2))  # 在k附近变化
        indices = set(random.sample(range(n), size))
        hv = compute_hv(indices)
        population.append((indices, hv))

    # 进化参数
    max_generations = 100
    mutation_rate = 0.3

    for generation in range(max_generations):
        # 环境选择：保留最好的个体
        population.sort(key=lambda x: x[1], reverse=True)
        population = population[:population_size]

        # 终止条件：找到大小为k且足够好的解
        best_k_solution = None
        best_k_hv = -np.inf
        for indices, hv in population:
            if len(indices) == k and hv > best_k_hv:
                best_k_solution = indices
                best_k_hv = hv

        # 如果连续10代没有改进，提前终止
        if generation > 10 and best_k_hv > 0:
            # 检查最近10代是否没有改进
            if all(abs(population[0][1] - best_k_hv) < 1e-6 for _ in range(min(10, generation))):
                if best_k_solution is not None:
                    return points[list(best_k_solution)]

        # 生成子代
        offspring = []
        for _ in range(population_size):
            # 选择父代（锦标赛选择）
            parent1_idx = random.randint(0, len(population)-1)
            parent2_idx = random.randint(0, len(population)-1)
            parent1 = population[parent1_idx][0]
            parent2 = population[parent2_idx][0]

            # 交叉（并集）
            child = parent1 | parent2

            # 变异
            if random.random() < mutation_rate:
                # 添加或删除点
                if len(child) > 1 and random.random() < 0.5:
                    # 删除贡献最小的点
                    if len(child) > 0:
                        contributions = []
                        for idx in child:
                            contrib = point_contribution(idx, child - {idx})
                            contributions.append((idx, contrib))
                        contributions.sort(key=lambda x: x[1])
                        if contributions:
                            child.remove(contributions[0][0])
                else:
                    # 添加点
                    if len(child) < n:
                        available = set(range(n)) - child
                        if available:
                            # 添加贡献最大的点
                            contributions = []
                            for idx in available:
                                contrib = point_contribution(idx, child)
                                contributions.append((idx, contrib))
                            contributions.sort(key=lambda x: x[1], reverse=True)
                            if contributions:
                                child.add(contributions[0][0])

            # 修复大小（如果偏离k太远）
            if len(child) > k + 3:
                # 删除贡献最小的点直到接近k
                while len(child) > k + 1:
                    contributions = []
                    for idx in child:
                        contrib = point_contribution(idx, child - {idx})
                        contributions.append((idx, contrib))
                    contributions.sort(key=lambda x: x[1])
                    if contributions:
                        child.remove(contributions[0][0])
            elif len(child) < k - 3 and len(child) < n:
                # 添加贡献最大的点直到接近k
                while len(child) < k - 1 and len(child) < n:
                    available = set(range(n)) - child
                    if available:
                        contributions = []
                        for idx in available:
                            contrib = point_contribution(idx, child)
                            contributions.append((idx, contrib))
                        contributions.sort(key=lambda x: x[1], reverse=True)
                        if contributions:
                            child.add(contributions[0][0])

            # 计算适应度
            child_hv = compute_hv(child)
            offspring.append((child, child_hv))

        # 合并种群
        population.extend(offspring)

    # 从最终种群中选择最好的大小为k的解
    best_solution = None
    best_hv = -np.inf
    for indices, hv in population:
        if len(indices) == k and hv > best_hv:
            best_solution = indices
            best_hv = hv

    # 如果没有找到大小为k的解，调整大小
    if best_solution is None:
        # 选择最接近k的解
        population.sort(key=lambda x: (abs(len(x[0]) - k), -x[1]))
        best_solution = population[0][0]

        # 调整到正好k个点
        if len(best_solution) > k:
            # 删除贡献最小的点
            while len(best_solution) > k:
                contributions = []
                for idx in best_solution:
                    contrib = point_contribution(idx, best_solution - {idx})
                    contributions.append((idx, contrib))
                contributions.sort(key=lambda x: x[1])
                if contributions:
                    best_solution.remove(contributions[0][0])
        elif len(best_solution) < k:
            # 添加贡献最大的点
            while len(best_solution) < k:
                available = set(range(n)) - best_solution
                if available:
                    contributions = []
                    for idx in available:
                        contrib = point_contribution(idx, best_solution)
                        contributions.append((idx, contrib))
                    contributions.sort(key=lambda x: x[1], reverse=True)
                    if contributions:
                        best_solution.add(contributions[0][0])

    return points[list(best_solution)]

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    n, d = points.shape

    # 缓存超体积计算
    hv_cache = {}

    def compute_hv(indices):
        key = tuple(sorted(indices))
        if key not in hv_cache:
            if not indices:
                hv_cache[key] = 0.0
            else:
                hv = pg.hypervolume(points[list(indices)])
                hv_cache[key] = hv.compute(reference_point)
        return hv_cache[key]

    # 1. 基于贡献的贪心初始化
    def greedy_by_contributions():
        selected = set()
        contributions = {}

        # 初始贡献：单个点的超体积
        for i in range(n):
            contributions[i] = compute_hv([i])

        while len(selected) < k:
            # 选择贡献最大的点
            best_idx = max((idx for idx in range(n) if idx not in selected), 
                          key=lambda x: contributions[x], default=None)

            if best_idx is None:
                # 如果没有候选点，随机选择一个
                remaining = [i for i in range(n) if i not in selected]
                if remaining:
                    best_idx = random.choice(remaining)
                else:
                    break

            selected.add(best_idx)

            # 更新剩余点的贡献估计
            if len(selected) < k:
                for i in range(n):
                    if i not in selected:
                        # 近似计算新贡献：与当前集合的边际贡献
                        new_set = list(selected) + [i]
                        old_hv = compute_hv(list(selected))
                        new_hv = compute_hv(new_set)
                        contributions[i] = new_hv - old_hv

        return list(selected)

    # 2. 迭代删除-添加优化
    def iterative_removal_addition(initial_set):
        current_set = set(initial_set)
        best_hv = compute_hv(list(current_set))

        improved = True
        while improved:
            improved = False

            # 删除阶段：移除贡献最小的点
            if len(current_set) > 1:
                worst_contrib = float('inf')
                worst_point = None

                for idx in current_set:
                    temp_set = current_set - {idx}
                    contrib = best_hv - compute_hv(list(temp_set))
                    if contrib < worst_contrib:
                        worst_contrib = contrib
                        worst_point = idx

                # 尝试移除贡献最小的点
                if worst_point is not None:
                    candidate_set = current_set - {worst_point}

                    # 添加阶段：寻找最佳替换点
                    best_add = None
                    best_add_hv = -float('inf')

                    for i in range(n):
                        if i not in candidate_set:
                            new_set = list(candidate_set) + [i]
                            new_hv = compute_hv(new_set)
                            if new_hv > best_add_hv:
                                best_add_hv = new_hv
                                best_add = i

                    if best_add is not None and best_add_hv > best_hv:
                        candidate_set.add(best_add)
                        current_set = candidate_set
                        best_hv = best_add_hv
                        improved = True

            # 如果没有改进，尝试随机扰动
            if not improved and len(current_set) == k:
                # 随机交换两个点
                for _ in range(min(10, n)):
                    remove_idx = random.choice(list(current_set))
                    candidate_set = current_set - {remove_idx}

                    available = [i for i in range(n) if i not in candidate_set]
                    if not available:
                        continue

                    add_idx = random.choice(available)
                    new_set = list(candidate_set) + [add_idx]
                    new_hv = compute_hv(new_set)

                    if new_hv > best_hv:
                        current_set = set(new_set)
                        best_hv = new_hv
                        improved = True
                        break

        return list(current_set)

    # 3. 邻域搜索优化
    def neighborhood_search(current_set):
        best_set = current_set.copy()
        best_hv = compute_hv(best_set)

        # 尝试所有可能的单点替换
        for i in range(len(best_set)):
            for j in range(n):
                if j in best_set:
                    continue

                new_set = best_set.copy()
                new_set[i] = j
                new_hv = compute_hv(new_set)

                if new_hv > best_hv:
                    best_set = new_set
                    best_hv = new_hv

        return best_set

    # 主算法流程
    # 步骤1: 贪心初始化
    initial_set = greedy_by_contributions()

    # 步骤2: 迭代删除-添加优化
    improved_set = iterative_removal_addition(initial_set)

    # 步骤3: 邻域搜索
    final_set = neighborhood_search(improved_set)

    # 确保返回k个点
    if len(final_set) != k:
        # 如果不足k个点，用贪心补充
        current = set(final_set)
        while len(current) < k:
            best_contrib = -float('inf')
            best_idx = None

            for i in range(n):
                if i not in current:
                    new_set = list(current) + [i]
                    contrib = compute_hv(new_set) - compute_hv(list(current))
                    if contrib > best_contrib:
                        best_contrib = contrib
                        best_idx = i

            if best_idx is not None:
                current.add(best_idx)
            else:
                break

        final_set = list(current)

    return points[final_set]

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np
    import pygmo as pg

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    n, d = points.shape

    def compute_hv(point_set):
        if len(point_set) == 0:
            return 0.0
        hv = pg.hypervolume(np.array(point_set))
        return hv.compute(reference_point)

    selected_indices = []
    selected_points = []
    hv_cache = {}

    while len(selected_indices) < k:
        best_contrib = -np.inf
        best_idx = None

        for idx in range(n):
            if idx in selected_indices:
                continue

            point = points[idx]
            key_before = tuple(sorted(selected_indices))
            key_after = tuple(sorted(selected_indices + [idx]))

            if key_before not in hv_cache:
                hv_cache[key_before] = compute_hv(selected_points)
            if key_after not in hv_cache:
                hv_after = compute_hv(selected_points + [point])
                hv_cache[key_after] = hv_after
            else:
                hv_after = hv_cache[key_after]

            contrib = hv_after - hv_cache[key_before]

            if contrib > best_contrib:
                best_contrib = contrib
                best_idx = idx

        if best_idx is not None:
            selected_indices.append(best_idx)
            selected_points.append(points[best_idx])
        else:
            remaining = [i for i in range(n) if i not in selected_indices]
            if remaining:
                idx = remaining[0]
                selected_indices.append(idx)
                selected_points.append(points[idx])
            else:
                break

    population = [selected_indices.copy()]
    fitness = [compute_hv(selected_points)]
    pop_size = 1
    max_pop = 10

    def size_aware_mutation(indices):
        indices = indices.copy()
        b = len(indices)
        a = n - b

        if b < k:
            add_prob = (k - b + 1) / (2 * a) if a > 0 else 0
            remove_prob = 0
        elif b > k:
            add_prob = 0
            remove_prob = (b - k + 1) / (2 * b) if b > 0 else 0
        else:
            add_prob = 1 / (2 * a) if a > 0 else 0
            remove_prob = 1 / (2 * b) if b > 0 else 0

        if np.random.rand() < add_prob and a > 0:
            unselected = [i for i in range(n) if i not in indices]
            if unselected:
                indices.append(np.random.choice(unselected))

        if np.random.rand() < remove_prob and b > 0:
            indices.pop(np.random.randint(len(indices)))

        return indices

    def environmental_selection(pop, fit, new_indices):
        new_size = len(new_indices)
        if new_size != k:
            return pop, fit

        for idx_set in pop:
            if set(idx_set) == set(new_indices):
                return pop, fit

        new_hv = compute_hv(points[new_indices])

        if len(pop) < max_pop:
            pop.append(new_indices)
            fit.append(new_hv)
        else:
            min_idx = np.argmin(fit)
            if new_hv > fit[min_idx]:
                pop[min_idx] = new_indices
                fit[min_idx] = new_hv

        return pop, fit

    iterations = min(100, 2 * n)
    for _ in range(iterations):
        parent_idx = np.random.randint(pop_size)
        offspring = size_aware_mutation(population[parent_idx])
        population, fitness = environmental_selection(population, fitness, offspring)
        pop_size = len(population)

    best_idx = np.argmax(fitness)
    selected_indices = population[best_idx]
    selected_points = points[selected_indices]

    improved = True
    while improved:
        improved = False

        for i in range(k):
            current_idx = selected_indices[i]
            current_hv = compute_hv(selected_points)

            for j in range(n):
                if j in selected_indices:
                    continue

                temp_indices = selected_indices.copy()
                temp_indices[i] = j
                temp_points = points[temp_indices]

                new_hv = compute_hv(temp_points)

                if new_hv > current_hv:
                    selected_indices = temp_indices
                    selected_points = temp_points
                    improved = True
                    break

        if not improved:
            break

    return np.array(selected_points)

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    n, d = points.shape
    population = []
    hv_cache = {}

    # 计算超体积（带缓存）
    def cached_hv(indices):
        key = tuple(sorted(indices))
        if key not in hv_cache:
            if not indices:
                hv_cache[key] = 0.0
            else:
                hv = pg.hypervolume(points[list(indices)])
                hv_cache[key] = hv.compute(reference_point)
        return hv_cache[key]

    # 生成初始解：反向贪心移除
    def backward_greedy():
        current = set(range(n))
        while len(current) > k:
            worst = None
            worst_loss = float('inf')
            current_hv = cached_hv(current)

            for idx in list(current):
                temp = current - {idx}
                loss = current_hv - cached_hv(temp)
                if loss < worst_loss:
                    worst_loss = loss
                    worst = idx
            if worst is not None:
                current.remove(worst)
        return current

    # 扰动操作
    def perturb(solution):
        new_sol = set(solution)
        if random.random() < 0.5 and len(new_sol) > 0:
            # 移除一个点
            remove_idx = random.choice(list(new_sol))
            new_sol.remove(remove_idx)
        if random.random() < 0.5 and len(new_sol) < n:
            # 添加一个点
            available = [i for i in range(n) if i not in new_sol]
            if available:
                new_sol.add(random.choice(available))
        # 确保大小正确
        while len(new_sol) > k:
            # 移除贡献最小的
            current_hv = cached_hv(new_sol)
            worst = None
            worst_loss = float('inf')
            for idx in list(new_sol):
                temp = new_sol - {idx}
                loss = current_hv - cached_hv(temp)
                if loss < worst_loss:
                    worst_loss = loss
                    worst = idx
            if worst is not None:
                new_sol.remove(worst)
        while len(new_sol) < k:
            # 添加贡献最大的
            available = [i for i in range(n) if i not in new_sol]
            if not available:
                break
            best = None
            best_gain = -float('inf')
            current_hv = cached_hv(new_sol)
            for idx in available:
                temp = new_sol | {idx}
                gain = cached_hv(temp) - current_hv
                if gain > best_gain:
                    best_gain = gain
                    best = idx
            if best is not None:
                new_sol.add(best)
        return new_sol

    # 局部交换优化
    def local_swap(solution):
        improved = True
        while improved:
            improved = False
            sol_list = list(solution)
            current_hv = cached_hv(solution)

            for i in range(len(sol_list)):
                for j in range(n):
                    if j in solution:
                        continue
                    new_sol = solution - {sol_list[i]} | {j}
                    new_hv = cached_hv(new_sol)
                    if new_hv > current_hv:
                        solution = new_sol
                        current_hv = new_hv
                        improved = True
                        break
                if improved:
                    break
        return solution

    # 生成初始种群
    for _ in range(5):
        sol = backward_greedy()
        sol = local_swap(sol)
        population.append((sol, cached_hv(sol)))

    # 迭代优化
    no_improve = 0
    while no_improve < 20:
        # 选择父代
        parent = max(population, key=lambda x: x[1])[0]

        # 扰动生成子代
        child = perturb(parent)
        child = local_swap(child)
        child_hv = cached_hv(child)

        # 更新种群（替换最差解）
        worst_idx = min(range(len(population)), key=lambda x: population[x][1])
        if child_hv > population[worst_idx][1]:
            population[worst_idx] = (child, child_hv)
            no_improve = 0
        else:
            no_improve += 1

    # 返回最佳解
    best_sol = max(population, key=lambda x: x[1])[0]
    return points[list(best_sol)]

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    n, d = points.shape

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # Hypervolume cache
    hv_cache: Dict[frozenset, float] = {}

    def compute_hv(indices: Set[int]) -> float:
        key = frozenset(indices)
        if key in hv_cache:
            return hv_cache[key]
        if not indices:
            hv = 0.0
        else:
            hv = pg.hypervolume(points[list(indices)]).compute(reference_point)
        hv_cache[key] = hv
        return hv

    # Initialize multiple solutions with different strategies
    population = []

    # Strategy 1: Greedy forward selection
    def greedy_forward():
        selected = set()
        while len(selected) < k:
            best_gain = -np.inf
            best_idx = -1
            for idx in range(n):
                if idx in selected:
                    continue
                candidate = selected | {idx}
                gain = compute_hv(candidate) - compute_hv(selected)
                if gain > best_gain:
                    best_gain = gain
                    best_idx = idx
            selected.add(best_idx)
        return selected

    # Strategy 2: Greedy backward elimination
    def greedy_backward():
        selected = set(range(n))
        while len(selected) > k:
            worst_loss = np.inf
            worst_idx = -1
            for idx in selected:
                candidate = selected - {idx}
                loss = compute_hv(selected) - compute_hv(candidate)
                if loss < worst_loss:
                    worst_loss = loss
                    worst_idx = idx
            selected.remove(worst_idx)
        return selected

    # Strategy 3: Random with local improvement
    def random_improved():
        selected = set(random.sample(range(n), k))
        improved = True
        while improved:
            improved = False
            current_hv = compute_hv(selected)
            # Try swaps
            for i in list(selected):
                for j in range(n):
                    if j in selected:
                        continue
                    candidate = (selected - {i}) | {j}
                    if compute_hv(candidate) > current_hv + 1e-10:
                        selected = candidate
                        improved = True
                        break
                if improved:
                    break
        return selected

    # Initialize population with diverse strategies
    population.append(greedy_forward())
    population.append(greedy_backward())
    for _ in range(8):
        population.append(random_improved())

    # Path relinking between solutions
    def path_relinking(source: Set[int], target: Set[int]) -> Set[int]:
        current = set(source)
        path = [current]

        # Elements to add and remove
        to_add = target - source
        to_remove = source - target

        # Create path by swapping elements
        while to_add or to_remove:
            best_step = None
            best_hv = -np.inf

            # Try all possible single swaps
            for add in to_add:
                for remove in to_remove:
                    candidate = (current - {remove}) | {add}
                    hv = compute_hv(candidate)
                    if hv > best_hv:
                        best_hv = hv
                        best_step = (add, remove)

            if best_step:
                add, remove = best_step
                current = (current - {remove}) | {add}
                to_add.remove(add)
                to_remove.remove(remove)
                path.append(current)
            else:
                break

        # Return best solution along the path
        best_set = max(path, key=lambda s: compute_hv(s))
        return best_set

    # Evolutionary loop with path relinking
    for generation in range(50):
        new_population = []

        # Generate new solutions through path relinking
        for i in range(len(population)):
            for j in range(i + 1, len(population)):
                # Relink in both directions
                new_sol1 = path_relinking(population[i], population[j])
                new_sol2 = path_relinking(population[j], population[i])
                new_population.extend([new_sol1, new_sol2])

        # Combine and select best
        combined = population + new_population
        hv_values = [compute_hv(s) for s in combined]
        top_indices = np.argsort(hv_values)[-10:]
        population = [combined[i] for i in top_indices]

    # Final intensive local search on best solution
    best_set = max(population, key=lambda s: compute_hv(s))
    best_hv = compute_hv(best_set)

    improved = True
    while improved:
        improved = False
        current_list = list(best_set)

        # Try all possible 2-opt swaps
        for i in range(k):
            for j in range(i + 1, k):
                for a in range(n):
                    if a in best_set:
                        continue
                    for b in range(n):
                        if b in best_set or a == b:
                            continue
                        temp_list = current_list.copy()
                        temp_list[i] = a
                        temp_list[j] = b
                        temp_set = set(temp_list)
                        if len(temp_set) == k:  # Ensure no duplicates
                            new_hv = compute_hv(temp_set)
                            if new_hv > best_hv + 1e-10:
                                best_set = temp_set
                                best_hv = new_hv
                                improved = True
                                break
                    if improved:
                        break
                if improved:
                    break
            if improved:
                break

    return points[list(best_set)]

